1: // liblex.zig — Vietnamese Telex input engine (prototype)
2: // Span-based composition engine. No diff/backspace logic — Swift handles diffing.
3: 
4: const std = @import("std");
5: 
6: // ── Data Structures ──────────────────────────────────────────────────
7: 
8: pub const Span = extern struct {
9:     base: u8, // ASCII base letter (a-z, A-Z)
10:     modifier: u8, // 0=none, 'w'=ư/ơ/ă, 'd'=đ, 'a'=â, 'e'=ê, 'o'=ô
11:     tone: u8, // 0=none, 's'=sắc, 'f'=huyền, 'r'=hỏi, 'x'=ngã, 'j'=nặng
12:     flags: u8, // bit 0: is_uppercase, bit 1: is_literal
13: };
14: 
15: pub const State = extern struct {
16:     spans: [24]Span,
17:     len: u8,
18:     mode: u8, // 0=NORMAL, 1=LITERAL
19:     _pad: [2]u8 = .{ 0, 0 },
20: };
21: 
22: // ── Unicode Lookup Tables ────────────────────────────────────────────
23: 
24: // Tone indices: 0=none, 1=s(sắc), 2=f(huyền), 3=r(hỏi), 4=x(ngã), 5=j(nặng)
25: 
26: // Lowercase: [no_tone, s, f, r, x, j]
27: const lut_a = [6]u16{ 0x0061, 0x00E1, 0x00E0, 0x1EA3, 0x00E3, 0x1EA1 };
28: const lut_aw = [6]u16{ 0x0103, 0x1EAF, 0x1EB1, 0x1EB3, 0x1EB5, 0x1EB7 }; // ă
29: const lut_aa = [6]u16{ 0x00E2, 0x1EA5, 0x1EA7, 0x1EA9, 0x1EAB, 0x1EAD }; // â
30: const lut_e = [6]u16{ 0x0065, 0x00E9, 0x00E8, 0x1EBB, 0x1EBD, 0x1EB9 };
31: const lut_ee = [6]u16{ 0x00EA, 0x1EBF, 0x1EC1, 0x1EC3, 0x1EC5, 0x1EC7 }; // ê
32: const lut_i = [6]u16{ 0x0069, 0x00ED, 0x00EC, 0x1EC9, 0x0129, 0x1ECB };
33: const lut_o = [6]u16{ 0x006F, 0x00F3, 0x00F2, 0x1ECF, 0x00F5, 0x1ECD };
34: const lut_oo = [6]u16{ 0x00F4, 0x1ED1, 0x1ED3, 0x1ED5, 0x1ED7, 0x1ED9 }; // ô
35: const lut_ow = [6]u16{ 0x01A1, 0x1EDB, 0x1EDD, 0x1EDF, 0x1EE1, 0x1EE3 }; // ơ
36: const lut_u = [6]u16{ 0x0075, 0x00FA, 0x00F9, 0x1EE7, 0x0169, 0x1EE5 };
37: const lut_uw = [6]u16{ 0x01B0, 0x1EE9, 0x1EEB, 0x1EED, 0x1EEF, 0x1EF1 }; // ư
38: const lut_y = [6]u16{ 0x0079, 0x00FD, 0x1EF3, 0x1EF7, 0x1EF9, 0x1EF5 };
39: 
40: // Uppercase
41: const lut_A = [6]u16{ 0x0041, 0x00C1, 0x00C0, 0x1EA2, 0x00C3, 0x1EA0 };
42: const lut_Aw = [6]u16{ 0x0102, 0x1EAE, 0x1EB0, 0x1EB2, 0x1EB4, 0x1EB6 };
43: const lut_Aa = [6]u16{ 0x00C2, 0x1EA4, 0x1EA6, 0x1EA8, 0x1EAA, 0x1EAC };
44: const lut_E = [6]u16{ 0x0045, 0x00C9, 0x00C8, 0x1EBA, 0x1EBC, 0x1EB8 };
45: const lut_Ee = [6]u16{ 0x00CA, 0x1EBE, 0x1EC0, 0x1EC2, 0x1EC4, 0x1EC6 };
46: const lut_I = [6]u16{ 0x0049, 0x00CD, 0x00CC, 0x1EC8, 0x0128, 0x1ECA };
47: const lut_O = [6]u16{ 0x004F, 0x00D3, 0x00D2, 0x1ECE, 0x00D5, 0x1ECC };
48: const lut_Oo = [6]u16{ 0x00D4, 0x1ED0, 0x1ED2, 0x1ED4, 0x1ED6, 0x1ED8 };
49: const lut_Ow = [6]u16{ 0x01A0, 0x1EDA, 0x1EDC, 0x1EDE, 0x1EE0, 0x1EE2 };
50: const lut_U = [6]u16{ 0x0055, 0x00DA, 0x00D9, 0x1EE6, 0x0168, 0x1EE4 };
51: const lut_Uw = [6]u16{ 0x01AF, 0x1EE8, 0x1EEA, 0x1EEC, 0x1EEE, 0x1EF0 };
52: const lut_Y = [6]u16{ 0x0059, 0x00DD, 0x1EF2, 0x1EF6, 0x1EF8, 0x1EF4 };
