335:             else => if (is_upper) &lut_O else &lut_o,
336:         },
337:         'u' => switch (modifier) {
338:             'w' => if (is_upper) &lut_Uw else &lut_uw,
339:             else => if (is_upper) &lut_U else &lut_u,
340:         },
341:         'y' => if (is_upper) &lut_Y else &lut_y,
342:         else => if (is_upper) &lut_A else &lut_a, // unreachable for vowels
