348: // ── Exported API ─────────────────────────────────────────────────────
349: 
350: export fn state_size() usize {
351:     return @sizeOf(State);
352: }
353: 
354: export fn init_state(state: *anyopaque) void {
355:     const s: *State = @ptrCast(@alignCast(state));
356:     s.* = std.mem.zeroes(State);
357: }
358: 
359: export fn reset(state: *anyopaque) void {
360:     const s: *State = @ptrCast(@alignCast(state));
361:     s.* = std.mem.zeroes(State);
362: }
363: 
364: export fn backspace(state: *anyopaque) u8 {
365:     const s: *State = @ptrCast(@alignCast(state));
366:     if (s.len == 0) return 0;
367:     s.len -= 1;
368:     // Clear the removed span
369:     s.spans[s.len] = std.mem.zeroes(Span);
370:     // If all spans removed, reset mode
371:     if (s.len == 0) s.mode = 0;
372:     return 1;
373: }
374: 
375: export fn add(state: *anyopaque, char_code: u16) u8 {
376:     const s: *State = @ptrCast(@alignCast(state));
377: 
378:     // Only handle ASCII range
379:     if (char_code > 127) {
380:         reset(state);
381:         return 0;
382:     }
383:     const ch: u8 = @intCast(char_code);
384: 
385:     // Non-alphanumeric → reset and passthrough
386:     if (!isAlpha(ch)) {
387:         reset(state);
388:         return 0;
389:     }
390: 
391:     const lo = toLower(ch);
392:     const is_upper = ch >= 'A' and ch <= 'Z';
393:     const flags: u8 = if (is_upper) 0x01 else 0x00;
394: 
395:     // ── LITERAL mode: just append ──
396:     if (s.mode == 1) {
397:         if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
398:         return 1;
399:     }
400: 
401:     // ── Check if first char triggers LITERAL mode ──
402:     if (s.len == 0) {
403:         if (lo == 'f' or lo == 'j' or lo == 'w' or lo == 'z') {
404:             enterLiteral(s);
405:             if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
406:             return 1;
407:         }
408:         // First char: just append as a regular span
409:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
410:         return 1;
411:     }
412: 
413:     // ── dd → đ ──
414:     if (lo == 'd') {
415:         // Look for last 'd' span without modifier
416:         if (s.len > 0) {
417:             const last_idx = s.len - 1;
418:             const last = &s.spans[last_idx];
419:             if (toLower(last.base) == 'd' and last.modifier == 0) {
420:                 // Cancellation: if already đ, undo
421:                 if (last.modifier == 'd') {
422:                     // Already handled above: modifier is 0 here
423:                     unreachable;
424:                 }
425:                 last.modifier = 'd';
426:                 return 1;
427:             }
428:         }
429:         // Regular d consonant
430:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
431:         autoFillUO(s);
432:         return 1;
433:     }
434: 
435:     // ── Doubled vowel modifier: aa→â, ee→ê, oo→ô ──
436:     if (lo == 'a' or lo == 'e' or lo == 'o') {
437:         if (s.len > 0) {
438:             const last_idx = s.len - 1;
439:             const last = &s.spans[last_idx];
440:             if (toLower(last.base) == lo and spanIsVowel(last.*)) {
441:                 if (last.modifier == lo) {
442:                     // Cancellation: modifier already applied → strip it, append plain vowel
443:                     last.modifier = 0;
444:                     last.tone = 0;
445:                     if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
446:                     return 1;
447:                 }
448:                 if (last.modifier == 0) {
449:                     last.modifier = lo;
450:                     return 1;
451:                 }
452:             }
453:         }
454:     }
455: 
456:     // ── w modifier ──
457:     if (lo == 'w') {
458:         // Look for target vowel: last a/o/u in the word
459:         var target: ?u8 = null;
460:         var i: u8 = 0;
461:         while (i < s.len) : (i += 1) {
462:             const b = toLower(s.spans[i].base);
463:             if (b == 'a' or b == 'o' or b == 'u') {
464:                 target = i;
465:             }
466:         }
467:         if (target) |ti| {
468:             const sp = &s.spans[ti];
469:             if (sp.modifier == 'w') {
470:                 // Cancellation: same modifier pressed again → enter literal
471:                 enterLiteral(s);
472:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
473:                 return 1;
474:             }
475:             if (sp.modifier != 0) {
476:                 // Already has a different modifier, can't apply w
477:                 // Treat w as a regular character → literal
478:                 enterLiteral(s);
479:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
480:                 return 1;
481:             }
482:             sp.modifier = 'w';
483:             // Re-apply tone placement since modified vowel changed
484:             const ct = currentTone(s);
485:             if (ct != 0) applyTone(s, ct);
486:             return 1;
487:         }
488:         // No target vowel: if at start or no vowels, enter literal
489:         enterLiteral(s);
490:         if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
491:         return 1;
492:     }
493: 
494:     // ── Tone marks: s, f, r, x, j ──
495:     if (lo == 's' or lo == 'f' or lo == 'r' or lo == 'x' or lo == 'j') {
496:         const r = computeRegions(s);
497:         if (r.has_nucleus) {
498:             const ct = currentTone(s);
499:             if (ct == lo) {
500:                 // Cancellation: same tone pressed again → strip tone, enter literal
501:                 enterLiteral(s);
502:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
503:                 return 1;
504:             }
505:             applyTone(s, lo);
506:             return 1;
507:         }
508:         // No nucleus vowels: treat as consonant
509:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
510:         return 1;
511:     }
512: 
513:     // ── z: tone reset or literal ──
514:     if (lo == 'z') {
515:         const ct = currentTone(s);
516:         if (ct != 0) {
517:             // Remove tone from all vowels
518:             var i: u8 = 0;
519:             while (i < s.len) : (i += 1) {
520:                 if (spanIsVowel(s.spans[i])) {
521:                     s.spans[i].tone = 0;
522:                 }
523:             }
524:             return 1;
525:         }
526:         // No tone to reset → enter literal
527:         enterLiteral(s);
528:         if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
529:         return 1;
530:     }
531: 
532:     // ── Vowels ──
533:     if (isVowel(lo)) {
534:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
535:         // Re-apply tone placement after adding a vowel
536:         const ct = currentTone(s);
537:         if (ct != 0) applyTone(s, ct);
538:         return 1;
539:     }
540: 
541:     // ── Consonants ──
542:     if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
543:     autoFillUO(s);
544:     return 1;
545: }
