547: export fn get_composed_utf16(state: *anyopaque, buf: [*]u16, buf_len: u16) u16 {
548:     const s: *State = @ptrCast(@alignCast(state));
549:     var pos: u16 = 0;
550: 
551:     var i: u8 = 0;
552:     while (i < s.len) : (i += 1) {
553:         if (pos >= buf_len) return 0xFF; // buffer overflow
554: 
555:         const sp = s.spans[i];
556: 
557:         // Literal spans: emit raw base character
558:         if (sp.flags & 0x02 != 0) {
559:             buf[pos] = @intCast(sp.base);
560:             pos += 1;
561:             continue;
562:         }
563: 
564:         const cp = lookupCodepoint(sp.base, sp.modifier, sp.tone);
565:         buf[pos] = cp;
566:         pos += 1;
567:     }
568: 
569:     return pos;
570: }

