const std = @import("std");

// Inline the exported functions we need by calling through C ABI
extern fn init_state(state: *anyopaque) void;
extern fn reset(state: *anyopaque) void;
extern fn add(state: *anyopaque, char_code: u16) u8;
extern fn get_composed_utf16(state: *anyopaque, buf: [*]u16, buf_len: u16) u16;
extern fn state_size() usize;

fn toUtf8(out: []u8, utf16: []const u16) usize {
    var pos: usize = 0;
    for (utf16) |cp16| {
        const cp: u21 = cp16;
        if (cp < 0x80) {
            out[pos] = @intCast(cp);
            pos += 1;
        } else if (cp < 0x800) {
            out[pos] = @intCast(0xC0 | (cp >> 6));
            out[pos + 1] = @intCast(0x80 | (cp & 0x3F));
            pos += 2;
        } else {
            out[pos] = @intCast(0xE0 | (cp >> 12));
            out[pos + 1] = @intCast(0x80 | ((cp >> 6) & 0x3F));
            out[pos + 2] = @intCast(0x80 | (cp & 0x3F));
            pos += 3;
        }
    }
    return pos;
}

fn testInput(writer: anytype, label: []const u8, chars: []const u8) !void {
    var state_buf: [256]u8 align(16) = undefined;
    const s: *anyopaque = &state_buf;
    init_state(s);
    for (chars) |c| {
        _ = add(s, c);
    }
    var buf: [64]u16 = undefined;
    const len = get_composed_utf16(s, &buf, 64);
    var utf8_buf: [256]u8 = undefined;
    const utf8_len = toUtf8(&utf8_buf, buf[0..len]);
    try writer.print("{s} => {s}\n", .{label, utf8_buf[0..utf8_len]});
}

pub fn main() !void {
    const w = std.io.getStdOut().writer();
    try testInput(w, "uowi", "uowi");
    try testInput(w, "uown", "uown");
    try testInput(w, "uoiw", "uoiw");
    try testInput(w, "huowu", "huowu");
}
